<script setup>
import {Icon} from "@iconify/vue";
import ModalComponent from "../components/ModalComponent";
import WeekViewEventCard from "../components/WeekViewEventCard";
import moment from "moment";
import {useRoute, useRouter} from "vue-router";
import {defineComponent, onMounted, ref} from "vue";
import axios from "../plugins/axios";

defineComponent({Icon,WeekViewEventCard,ModalComponent})

const router = useRouter()
const route = useRoute()

const firstTimeSlotEvent= ref(null)
const eventsFromServer = [
  {
  id:1,
  title:'Топшириқ 1',
  address:'Address 1',
  status:['yopiq','maxfiy'],
  startTime:'2022-01-13T09:00:00',
  endTime:'2022-01-13T10:00:00',
},{
  id:2,
  title:'Топшириқ 2',
  address:'Address 1',
  status:['yopiq','maxfiy'],
  startTime:'2022-01-13T09:00:00',
  endTime:'2022-01-13T10:00:00',
},{
  id:3,
  title:'Топшириқ 3',
  address:'Address 1',
  status:['yopiq','maxfiy'],
  startTime:'2022-01-13T11:45:00',
  endTime:'2022-01-13T12:00:00',
},{
  id:4,
  title:'Топшириқ 4',
  address:'Address 1',
  status:['yopiq','maxfiy'],
  startTime:'2022-01-13T13:05:00',
  endTime:'2022-01-13T13:35:00',
},]
const  weeks = ref([])
const eventsObject = ref({
  Monday: {},
  Tuesday:{},
  Wednesday:{},
  Thursday:{},
  Friday:{},
  Saturday:{},
  Sunday:{},
})

onMounted(async()=>{
  let startOfWeek = moment().startOf('isoweek').toDate();
  let endOfWeek   = moment().endOf('isoweek').toDate();
  generateWeeks(startOfWeek,endOfWeek)
  await getEventsByWeekPeriod(startOfWeek,endOfWeek)
  scrollToElemById(firstTimeSlotEvent.value?.id)
})


function scrollToElemById(elemId){
  let elem =  document.getElementById(elemId)
  if(elem){
    elem?.scrollIntoView({behavior: 'smooth', block: "center"});
  }
}

async function getEventsByWeekPeriod(start,end){
  const resp = (await axios.get('/api/event/all/by-period',{
    params:{
      startDate : moment(start).format('YYYY-MM-DD'),
      endDate : moment(end).format('YYYY-MM-DD'),
      viceId: route.params.id && route.params.id !=="undefined" ? route.params.id :""
    }
  })).data.data
  prepareEvents(resp)
}

function dayBtnClick(){
  router.push('/day/'+moment(new Date()).format('YYYY-MM-DD')+'/'+route.params.id)
}
function monthBtnClick(){
  router.push('/vice/'+route.params.id)
}

async function loadPrevWeek(){
  let startOfNextWeek =  moment(weeks.value[0]).add(-7,'days')
  let endOfNextWeek =  moment(startOfNextWeek).add(6,'days')
  generateWeeks(startOfNextWeek,endOfNextWeek)
  await getEventsByWeekPeriod(startOfNextWeek,endOfNextWeek)
  scrollToElemById(firstTimeSlotEvent.value?.id)
}
async function loadNextWeek(){
  let startOfNextWeek =  moment(weeks.value[6]).add(1,'days')
  let endOfNextWeek =  moment(startOfNextWeek).add(6,'days')
  generateWeeks(startOfNextWeek,endOfNextWeek)
  await getEventsByWeekPeriod(startOfNextWeek,endOfNextWeek)
  scrollToElemById(firstTimeSlotEvent.value?.id)
}
function generateWeeks(start,end){
  weeks.value = []
  let dayIterator = start;
  while (dayIterator<=end){
    weeks.value.push(dayIterator)
    dayIterator  = moment(dayIterator).add(1,'days')
  }
}


function prepareEvents(eventsArray){
  moment.locale('en');
  const weekEvents = {
    Monday: [],
    Tuesday:[],
    Wednesday:[],
    Thursday:[],
    Friday:[],
    Saturday:[],
    Sunday:[],
  }
  firstTimeSlotEvent.value = eventsArray[0]
  eventsArray.forEach(event=>{
    if(event.startTime <= firstTimeSlotEvent.value?.startTime){
      firstTimeSlotEvent.value = event // to scroll onMounted to first event at timeSlot
    }
    let weekDayName = moment(event.startTime).format('dddd')
    weekEvents[weekDayName].push(event)
  })
  const eventsObjectClone = {
    Monday: {},
    Tuesday:{},
    Wednesday:{},
    Thursday:{},
    Friday:{},
    Saturday:{},
    Sunday:{},
  }
  for (const [weekDay,events] of Object.entries(weekEvents)) {
    eventsObjectClone[weekDay] = makeTimeSlotEvents(events)
  }
  for (const [weekName,eventsTimeSlots] of Object.entries(eventsObjectClone)) {
    eventsObject.value[weekName] = stylizeEvents(eventsTimeSlots)
  }
  moment.locale('uz-latn');
}

function addStyleToEvent(arr){
  return arr.map(event=>{
    let borderColor = ''
    let backgroundColor = ''

    if(event.isImportant){
      borderColor = '#D55A00'
      backgroundColor = '#FBEEE5'
    } else if(event.isPrivate){
      borderColor='#03A600'
      backgroundColor='#E6F6E5'
    } else{
      borderColor='#007BED'
      backgroundColor='#E5F2FD'
    }

    return {
      ...event,
      styleObject:{
        zIndex : addZetIndex(),
        height : 90+'px !important',
        marginTop:(getMinutesFromDate(event.endTime)*2 -45)+'px',
        borderColor,
        backgroundColor
      }
    }
  })
}

const zIndex = ref(1)

function getMinutesFromDate(startTime){
  let m = moment(Date.parse(startTime));
  return  (m.hour()*60) + m.minute()
}
function addZetIndex(){
  zIndex.value= zIndex.value + 1
  return zIndex.value
}


function stylizeEvents(eventsListObject){
  let normalizedEventListObject = {}
  for (const [key , value] of Object.entries(eventsListObject)) {
    normalizedEventListObject[key] = addStyleToEvent(value)
  }
  return normalizedEventListObject
}
function makeTimeSlotEvents(arr){
  const startTimes = {}
  for (const event of arr) {
    const eventStartTime = event.startTime
    const sTime = moment(eventStartTime).format('HH:mm')
    if( !Object.keys(startTimes).includes(sTime) ){
      startTimes[sTime] = [event] // save in ISO string
    } else {
      startTimes[sTime] = [...startTimes[sTime],event]
    }
  }
  return startTimes
}

const eventInfoForModal = ref(null)


const modalComponentRef = ref(null)

function clickEvent(eventObject){
  modalComponentRef.value.openModal()
  eventInfoForModal.value = eventObject
}

function onCloseModal(){
  eventInfoForModal.value = null
}



